create table dirkspzm32.lvs_lhm (
    sid                  varchar2(2 char) default '01' not null enable,
    firma_nr             number(2, 0) default 1 not null enable,
    lhm_id               varchar2(20 char) not null enable,
    lte_id               varchar2(20 char),
    lhm_name             varchar2(50 char),
    lgr_platz            varchar2(30 char),
    lhm_vol_hoehe        number(*, 3),
    lhm_vol_breite       number(*, 3),
    lhm_vol_tiefe        number(*, 3),
    lhm_vol              number(*, 5),
    lhm_akt_kg           number(*, 6),
    lhm_letzte_buchung   date,
    lhm_eti_druck_status varchar2(10 char),
    komm_quell_lte_id    varchar2(20 char),
    komm_quell_lgr_platz varchar2(30 char),
    komm_neu_lhm_name    varchar2(50 char)
);

alter table dirkspzm32.lvs_lhm
    add constraint pk_lvs_lhm primary key ( lhm_id )
        using index enable;

alter table dirkspzm32.lvs_lhm
    add constraint uk_lvs_lhm_te unique ( lte_id,
                                          lhm_id )
        using index enable;


